import React, { useEffect } from 'react';
import { useLocation, Navigate } from 'react-router-dom';
import { TasksPane } from '@/features/tasks/components/TasksPane/TasksPane';
import { GenerationsPane } from '@/features/gallery/components/GenerationsPane/GenerationsPane';
import { EditorPane } from '@/features/editor/components/EditorPaneTab';
import { ToolsPane } from '@/shared/components/ToolsPane/ToolsPane';
import { usePanes } from '@/shared/contexts/PanesContext';
import { ReighLoading } from '@/shared/components/ReighLoading';
import { SettingsModal } from '@/shared/components/SettingsModal/SettingsModal';
import { OnboardingModal } from '@/shared/components/modals/OnboardingModal';
import { ChunkLoadErrorBoundary } from '@/shared/runtime/ChunkLoadErrorBoundary';
import { dispatchAppEvent } from '@/shared/lib/typedEvents';

// Lazy load ProductTour since it only shows during onboarding
const LazyProductTour = React.lazy(() =>
  import('@/shared/components/ProductTour').then(module => ({
    default: module.ProductTour
  }))
);
import { AIInputModeProvider } from '@/shared/contexts/AIInputModeContext';
import { useIsMobile, useIsTablet } from '@/shared/hooks/mobile';
import { SocialIcons } from './components/SocialIcons';

import { useAuth } from '@/shared/contexts/AuthContext';
import { useSplitViewScroll } from './hooks/useSplitViewScroll';
import { useSettingsModal } from './hooks/useSettingsModal';
import { useOnboardingFlow } from './hooks/useOnboardingFlow';
import { useResetCurrentShotOnRouteChange } from './hooks/useResetCurrentShotOnRouteChange';
import { LayoutMainContent } from './components/LayoutMainContent';

// Scroll to top component
function ScrollToTop() {
  const { pathname } = useLocation();

  useEffect(() => {
    window.scrollTo(0, 0);
    // Also dispatch event for custom scroll containers
    dispatchAppEvent('app:scrollToTop', { behavior: 'auto' });
  }, [pathname]);

  return null;
}

export const Layout: React.FC = () => {
  const {
    isTasksPaneLocked,
    tasksPaneWidth,
    isShotsPaneLocked,
    shotsPaneWidth,
    isGenerationsPaneLocked,
    generationsPaneHeight
  } = usePanes();

  // Mobile detection for split-view scroll handling
  const isMobile = useIsMobile();
  const isTablet = useIsTablet();
  const isSmallMobile = isMobile && !isTablet;

  // On small mobile with locked generations pane, create split-view scroll behavior
  const isMobileSplitView = isSmallMobile && isGenerationsPaneLocked;

  // Extracted hooks
  const { splitViewWrapperRef } = useSplitViewScroll(isMobileSplitView);
  const { isAuthenticated, isLoading } = useAuth();
  const { isSettingsModalOpen, setIsSettingsModalOpen, settingsInitialTab, settingsCreditsTab, handleOpenSettings } = useSettingsModal();
  const { showOnboardingModal, handleOnboardingClose } = useOnboardingFlow();
  useResetCurrentShotOnRouteChange();

  // Show loading spinner while determining auth state
  // (isLoading is always false here because AuthGate gates on it, but kept for safety)
  if (isLoading) {
    return (
      <ReighLoading />
    );
  }

  // Redirect unauthenticated users to home page
  // Use /home instead of / to avoid redirect loops in non-WEB environments
  // where / is inside Layout
  if (!isAuthenticated) {
    return <Navigate to="/home" replace state={{ fromProtected: true }} />;
  }

  // Footer style matches main content margins for side panes
  const footerStyle = {
    marginRight: isTasksPaneLocked ? `${tasksPaneWidth}px` : '0px',
    marginLeft: isShotsPaneLocked ? `${shotsPaneWidth}px` : '0px',
    willChange: 'margin',
  } as React.CSSProperties;

  // Style for the scroll wrapper when in mobile split view
  // This wraps both header and content so they scroll together
  const splitViewWrapperStyle: React.CSSProperties = isMobileSplitView ? {
    height: `calc(100dvh - ${generationsPaneHeight}px)`,
    overflowY: 'auto',
    overscrollBehavior: 'contain',
    WebkitOverflowScrolling: 'touch',
  } : {};

  const mainContent = (
    <LayoutMainContent
      isMobileSplitView={isMobileSplitView}
      onOpenSettings={handleOpenSettings}
    />
  );

  return (
    <AIInputModeProvider>
      <div className="flex flex-col">
        <ScrollToTop />
        {/* Theme-adaptive background gradient - subtle in dark mode */}
        <div className="fixed inset-0 bg-gradient-to-br from-background via-secondary/10 to-accent/5 opacity-40 dark:opacity-0 pointer-events-none"></div>

        {/* When in mobile split view, wrap header + content in a scroll container */}
        {isMobileSplitView ? (
          <div ref={splitViewWrapperRef} style={splitViewWrapperStyle}>
            {mainContent}
          </div>
        ) : (
          mainContent
        )}

        <EditorPane />
        <TasksPane onOpenSettings={handleOpenSettings} />
        <ToolsPane />
        <GenerationsPane />

        {/* Social Icons Footer */}
        <div
          className="relative transition-[margin] duration-300 ease-smooth"
          style={footerStyle}
        >
          <SocialIcons />
        </div>

        <SettingsModal
          isOpen={isSettingsModalOpen}
          onOpenChange={setIsSettingsModalOpen}
          initialTab={settingsInitialTab}
          creditsTab={settingsCreditsTab}
        />

        {/* Onboarding Modal */}
        <OnboardingModal
          isOpen={showOnboardingModal}
          onClose={handleOnboardingClose}
        />

        {/* Product Tour - lazy loaded since only needed during onboarding */}
        <ChunkLoadErrorBoundary>
          <React.Suspense fallback={null}>
            <LazyProductTour />
          </React.Suspense>
        </ChunkLoadErrorBoundary>
      </div>
    </AIInputModeProvider>
  );
};

import type { CSSProperties } from 'react';
import { Outlet } from 'react-router-dom';
import { GlobalHeader } from '@/shared/components/GlobalHeader';
import { GlobalProcessingWarning } from '@/shared/components/ProcessingWarnings';
import { usePanes } from '@/shared/contexts/PanesContext';
import { useHeaderState } from '@/shared/contexts/ToolPageHeaderContext';
import { useViewportResponsive } from '@/shared/hooks/responsive/useViewportResponsive';
import { cn } from '@/shared/components/ui/contracts/cn';

interface LayoutMainContentProps {
  isMobileSplitView: boolean;
  onOpenSettings: (initialTab?: string, creditsTab?: 'purchase' | 'history') => void;
}

export function LayoutMainContent(props: LayoutMainContentProps) {
  const { isMobileSplitView, onOpenSettings } = props;
  const {
    isTasksPaneLocked,
    tasksPaneWidth,
    isShotsPaneLocked,
    shotsPaneWidth,
    isGenerationsPaneLocked,
    isGenerationsPaneOpen,
    effectiveGenerationsPaneHeight,
    isEditorPaneLocked,
    isEditorPaneOpen,
    effectiveEditorPaneHeight,
  } = usePanes();
  const { header } = useHeaderState();
  const { isSm, isMd, isLg, isXl, is2Xl, contentWidth, contentHeight } = useViewportResponsive();

  const containerPadding = isLg ? 'px-6' : isSm ? 'px-4' : 'px-2';
  const containerSpacing = 'py-1';

  const contentStyle = {
    marginRight: isTasksPaneLocked ? `${tasksPaneWidth}px` : '0px',
    marginLeft: isShotsPaneLocked ? `${shotsPaneWidth}px` : '0px',
    paddingTop: (isEditorPaneLocked || isEditorPaneOpen) ? `${effectiveEditorPaneHeight}px` : '0px',
    paddingBottom: isMobileSplitView ? '0px' : ((isGenerationsPaneLocked || isGenerationsPaneOpen) ? `${effectiveGenerationsPaneHeight}px` : '0px'),
    '--content-width': `${contentWidth}px`,
    '--content-height': `${contentHeight}px`,
    '--content-sm': isSm ? '1' : '0',
    '--content-md': isMd ? '1' : '0',
    '--content-lg': isLg ? '1' : '0',
    '--content-xl': isXl ? '1' : '0',
    '--content-2xl': is2Xl ? '1' : '0',
    willChange: 'margin, padding',
  } as CSSProperties;

  return (
    <>
      <GlobalHeader
        contentOffsetRight={isTasksPaneLocked ? tasksPaneWidth + 16 : 16}
        contentOffsetLeft={isShotsPaneLocked ? shotsPaneWidth : 0}
        onOpenSettings={onOpenSettings}
      />

      <div
        className="relative z-10 transition-[margin,padding] duration-300 ease-smooth content-container"
        style={contentStyle}
      >
        <GlobalProcessingWarning onOpenSettings={onOpenSettings} />

        <main className={cn('container mx-auto', containerPadding, containerSpacing)}>
          {header}
          <Outlet />
        </main>
      </div>
    </>
  );
}

import React from 'react';
import { ExternalLink } from 'lucide-react';
import { useLocation, useNavigate } from 'react-router-dom';
import { cn } from '@/shared/components/ui/contracts/cn';
import { PaneControlTab } from '@/shared/components/PaneControlTab';
import { useSlidingPane } from '@/shared/hooks/useSlidingPane';
import { usePanes } from '@/shared/contexts/PanesContext';
import { useAuth } from '@/shared/contexts/AuthContext';
import { useProjectSelectionContext } from '@/shared/contexts/ProjectContext';
import { useToolSettings } from '@/shared/hooks/settings/useToolSettings';
import { Button } from '@/shared/components/ui/button';
import { SupabaseDataProvider } from '@/tools/video-editor/data/SupabaseDataProvider';
import { VideoEditorProvider } from '@/tools/video-editor/contexts/VideoEditorProvider';
import { useTimelinesList } from '@/tools/video-editor/hooks/useTimelinesList';
import { videoEditorSettings } from '@/tools/video-editor/settings/videoEditorDefaults';
import { VideoEditorShell } from '@/tools/video-editor/components/VideoEditorShell';

function useEditorPane() {
  const {
    isEditorPaneLocked,
    setIsEditorPaneLocked,
    setIsEditorPaneOpen,
    effectiveEditorPaneHeight,
    isShotsPaneLocked,
    shotsPaneWidth,
    isTasksPaneLocked,
    tasksPaneWidth,
  } = usePanes();

  const pane = useSlidingPane({
    side: 'top',
    isLocked: isEditorPaneLocked,
    onToggleLock: () => setIsEditorPaneLocked(!isEditorPaneLocked),
    onOpenChange: setIsEditorPaneOpen,
  });

  return {
    pane,
    effectiveEditorPaneHeight,
    isShotsPaneLocked,
    shotsPaneWidth,
    isTasksPaneLocked,
    tasksPaneWidth,
  };
}

const EditorPaneComponent: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { selectedProjectId } = useProjectSelectionContext();
  const { userId } = useAuth();
  const { settings, update } = useToolSettings(videoEditorSettings.id, {
    projectId: selectedProjectId ?? undefined,
    enabled: Boolean(selectedProjectId),
  });
  const timelines = useTimelinesList(selectedProjectId, userId);
  const {
    pane,
    effectiveEditorPaneHeight,
    isShotsPaneLocked,
    shotsPaneWidth,
    isTasksPaneLocked,
    tasksPaneWidth,
  } = useEditorPane();

  if (location.pathname === '/tools/video-editor') {
    return null;
  }

  const horizontalOffset =
    (isShotsPaneLocked ? shotsPaneWidth : 0) -
    (isTasksPaneLocked ? tasksPaneWidth : 0);
  const activeTimelineId = settings?.lastTimelineId ?? timelines.data?.[0]?.id ?? null;
  const provider = selectedProjectId && userId
    ? new SupabaseDataProvider({ projectId: selectedProjectId, userId })
    : null;
  const createTimeline = async () => {
    const created = await timelines.createTimeline.mutateAsync('Main timeline');
    await update('project', { lastTimelineId: created.id });
    navigate(`/tools/video-editor?timeline=${created.id}`);
  };

  return (
    <>
      {/* Control tab */}
      <PaneControlTab
        position={{
          side: 'top',
          paneDimension: effectiveEditorPaneHeight,
          horizontalOffset,
        }}
        state={{ isLocked: pane.isLocked, isOpen: pane.isOpen }}
        handlers={{
          toggleLock: pane.toggleLock,
          openPane: pane.openPane,
          handlePaneEnter: pane.handlePaneEnter,
          handlePaneLeave: pane.handlePaneLeave,
        }}
        display={{
          paneTooltip: 'Open editor',
        }}
        actions={{
          thirdButton: {
            onClick: () => {
              if (activeTimelineId) {
                navigate(`/tools/video-editor?timeline=${activeTimelineId}`);
                return;
              }
              navigate('/tools/video-editor');
            },
            ariaLabel: 'Go to editor',
            tooltip: 'Go to editor',
            content: <ExternalLink className="h-4 w-4" />,
          },
        }}
      />

      {/* Pane surface */}
      <div
        {...pane.paneProps}
        data-testid="editor-pane"
        style={{
          height: `${effectiveEditorPaneHeight}px`,
          left: isShotsPaneLocked ? `${shotsPaneWidth}px` : 0,
          right: isTasksPaneLocked ? `${tasksPaneWidth}px` : 0,
          zIndex: 59,
        }}
        className={cn(
          'fixed top-0 bg-zinc-900/95 border-b border-zinc-700 shadow-xl transform transition-transform duration-300 ease-smooth flex flex-col pointer-events-auto',
          pane.transformClass,
        )}
      >
        {provider && userId && activeTimelineId ? (
          <VideoEditorProvider dataProvider={provider} timelineId={activeTimelineId} userId={userId}>
            <VideoEditorShell mode="compact" timelineId={activeTimelineId} onCreateTimeline={() => void createTimeline()} />
          </VideoEditorProvider>
        ) : (
          <div className="flex h-full items-center justify-center">
            <div className="rounded-xl border border-dashed border-zinc-700 bg-zinc-900/70 p-6 text-center">
              <div className="text-sm font-medium text-zinc-100">No active timeline</div>
              <div className="mt-1 text-xs text-zinc-400">Create one in the standalone editor or from this pane.</div>
              <div className="mt-4 flex justify-center gap-2">
                <Button type="button" size="sm" onClick={() => void createTimeline()} disabled={!selectedProjectId || !userId}>
                  Create timeline
                </Button>
                <Button type="button" size="sm" variant="outline" onClick={() => navigate('/tools/video-editor')}>
                  Open editor
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
};

export const EditorPane = React.memo(EditorPaneComponent);

import { memo, useCallback, useRef, useState, type MouseEvent as ReactMouseEvent } from 'react';
import { Download, Type, Video, Volume2, ZoomIn, ZoomOut } from 'lucide-react';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/shared/components/ui/alert-dialog';
import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import { CompactPreview } from '@/tools/video-editor/components/CompactPreview';
import { PreviewPanel } from '@/tools/video-editor/components/PreviewPanel/PreviewPanel';
import { PropertiesPanel } from '@/tools/video-editor/components/PropertiesPanel/PropertiesPanel';
import { TimelineEditor } from '@/tools/video-editor/components/TimelineEditor/TimelineEditor';
import { useTimelineChromeContext } from '@/tools/video-editor/contexts/TimelineChromeContext';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { useTimelinePlaybackContext } from '@/tools/video-editor/contexts/TimelinePlaybackContext';
import { useKeyboardShortcuts } from '@/tools/video-editor/hooks/useKeyboardShortcuts';
import { useTimelineRealtime } from '@/tools/video-editor/hooks/useTimelineRealtime';

const MIN_TIMELINE_HEIGHT = 140;
const MIN_PREVIEW_HEIGHT = 180;
const STATUS_VARIANT = {
  saved: 'default',
  saving: 'secondary',
  dirty: 'outline',
  error: 'destructive',
} as const;

interface VideoEditorShellProps {
  mode: 'full' | 'compact';
  timelineId?: string | null;
  onCreateTimeline?: () => void;
}

function FullEditorLayout({ timelineId }: { timelineId: string }) {
  const editor = useTimelineEditorContext();
  const chrome = useTimelineChromeContext();
  const playback = useTimelinePlaybackContext();
  const containerRef = useRef<HTMLDivElement>(null);
  const dividerRef = useRef<HTMLDivElement>(null);
  const [timelineHeight, setTimelineHeight] = useState<number | null>(null);
  const conflict = useTimelineRealtime({
    timelineId,
    saveStatus: chrome.saveStatus,
    onDiscardRemoteChanges: chrome.reloadFromServer,
  });

  useKeyboardShortcuts({
    hasSelectedClip: Boolean(editor.selectedClipId),
    moveSelectedClipToTrack: editor.moveSelectedClipToTrack,
    togglePlayPause: () => playback.previewRef.current?.togglePlayPause(),
    seekRelative: (deltaSeconds) => playback.previewRef.current?.seek(Math.max(0, playback.currentTime + deltaSeconds)),
    toggleMute: editor.handleToggleMute,
    splitSelectedClip: editor.handleSplitSelectedClip,
    deleteSelectedClip: () => {
      if (editor.selectedClipId) {
        editor.handleDeleteClip(editor.selectedClipId);
      }
    },
    clearSelection: () => editor.setSelectedClipId(null),
  });

  const onDividerMouseDown = useCallback((event: ReactMouseEvent) => {
    event.preventDefault();
    const container = containerRef.current;
    const divider = dividerRef.current;
    if (!container || !divider) {
      return;
    }

    divider.classList.add('is-dragging');
    document.body.style.cursor = 'row-resize';
    document.body.style.userSelect = 'none';

    const onMouseMove = (moveEvent: MouseEvent) => {
      const rect = container.getBoundingClientRect();
      const nextHeight = Math.max(MIN_TIMELINE_HEIGHT, rect.bottom - moveEvent.clientY);
      if (rect.height - nextHeight < MIN_PREVIEW_HEIGHT) {
        return;
      }
      container.style.gridTemplateRows = `minmax(0,1fr) auto ${nextHeight}px`;
    };

    const onMouseUp = () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
      divider.classList.remove('is-dragging');
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      const match = container.style.gridTemplateRows.match(/(\d+)px$/);
      container.style.gridTemplateRows = '';
      if (match) {
        setTimelineHeight(Number.parseInt(match[1], 10));
      }
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
  }, []);

  return (
    <>
      <div className="flex h-full flex-col bg-zinc-950 text-zinc-100">
        <main
          ref={containerRef}
          className="grid min-h-0 flex-1 grid-cols-[minmax(0,1fr)_360px] gap-3 p-3"
          style={{ gridTemplateRows: timelineHeight ? `minmax(0,1fr) auto ${timelineHeight}px` : 'minmax(0,1fr) auto minmax(200px,36%)' }}
        >
          <div className="relative min-h-0">
            <div className="pointer-events-none absolute inset-x-0 top-0 z-20 flex items-center justify-between px-3 py-3">
              <div className="pointer-events-auto flex items-center gap-2">
                <Badge variant={STATUS_VARIANT[chrome.saveStatus]} className="h-5 px-1.5 text-[10px] capitalize">
                  {chrome.saveStatus}
                </Badge>
                <span className="font-mono text-[11px] tracking-[0.08em] text-zinc-400">{playback.formatTime(playback.currentTime)}</span>
              </div>
              <div className="pointer-events-auto flex items-center gap-1">
                <Button type="button" size="icon" variant="ghost" className="h-7 w-7" onClick={chrome.handleAddText}>
                  <Type className="h-3.5 w-3.5" />
                </Button>
                <Button type="button" size="sm" className="h-7 gap-1.5 px-3 text-[11px]" onClick={() => void chrome.startRender()}>
                  <Download className="h-3.5 w-3.5" />
                  Render
                </Button>
              </div>
            </div>
            <PreviewPanel />
          </div>

          <div className="row-span-2 min-h-0 overflow-hidden">
            <PropertiesPanel />
          </div>

          <div
            ref={dividerRef}
            className="col-span-1 flex cursor-row-resize items-center justify-center rounded hover:bg-zinc-900/60"
            style={{ height: 10, marginBlock: -2 }}
            onMouseDown={onDividerMouseDown}
          >
            <div className="h-1 w-12 rounded-full bg-zinc-700" />
          </div>

          <div className="col-span-2 flex min-h-0 flex-col gap-2 overflow-hidden">
            <div className="flex items-center justify-between px-1">
              <div className="flex items-center gap-1">
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.handleAddTrack('visual')}>
                  <Video className="h-3.5 w-3.5" />
                </Button>
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.handleAddTrack('audio')}>
                  <Volume2 className="h-3.5 w-3.5" />
                </Button>
                {chrome.unusedTrackCount > 0 && (
                  <Button type="button" variant="ghost" size="sm" className="h-7 px-2 text-[11px]" onClick={chrome.handleClearUnusedTracks}>
                    Clear {chrome.unusedTrackCount} unused
                  </Button>
                )}
              </div>
              <div className="flex items-center gap-1">
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.setScaleWidth((value) => Math.max(value / 1.4, 40))}>
                  <ZoomOut className="h-3.5 w-3.5" />
                </Button>
                <Button type="button" variant="ghost" size="icon" className="h-7 w-7" onClick={() => chrome.setScaleWidth((value) => Math.min(value * 1.4, 500))}>
                  <ZoomIn className="h-3.5 w-3.5" />
                </Button>
              </div>
            </div>
            <div className="min-h-0 flex-1 overflow-hidden">
              <TimelineEditor />
            </div>
          </div>
        </main>
      </div>

      <AlertDialog open={conflict.isOpen} onOpenChange={conflict.setOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Remote timeline changes detected</AlertDialogTitle>
            <AlertDialogDescription>
              Another tab updated this timeline while you still have unsaved local edits. Keep your local draft or discard it and reload the latest server version.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={conflict.keepLocalChanges}>Keep local draft</AlertDialogCancel>
            <AlertDialogAction onClick={() => void conflict.discardAndReload()}>Discard and reload</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

function VideoEditorShellComponent({ mode, timelineId, onCreateTimeline }: VideoEditorShellProps) {
  if (mode === 'compact') {
    return <CompactPreview timelineId={timelineId} onCreateTimeline={onCreateTimeline} />;
  }

  if (!timelineId) {
    return null;
  }

  return <FullEditorLayout timelineId={timelineId} />;
}

export const VideoEditorShell = memo(VideoEditorShellComponent);

import { useEffect, useMemo, useState } from 'react';
import { Clapperboard, Pencil, Plus, Trash2 } from 'lucide-react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Button } from '@/shared/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/shared/components/ui/card';
import { Input } from '@/shared/components/ui/input';
import { Skeleton } from '@/shared/components/ui/skeleton';
