function TimelineList({ onSelect }: { onSelect: (timelineId: string) => void }) {
  const { selectedProjectId } = useProjectSelectionContext();
  const { userId } = useAuth();
  const { settings, update } = useToolSettings(videoEditorSettings.id, {
    projectId: selectedProjectId ?? undefined,
    enabled: Boolean(selectedProjectId),
  });
  const timelines = useTimelinesList(selectedProjectId, userId);
  const [newName, setNewName] = useState('Main timeline');
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState('');
  const [autoCreating, setAutoCreating] = useState(false);

  // Auto-create a default timeline if the project has none
  useEffect(() => {
    if (
      !timelines.isLoading &&
      timelines.data &&
      timelines.data.length === 0 &&
      selectedProjectId &&
      userId &&
      !autoCreating &&
      !timelines.createTimeline.isPending
    ) {
      setAutoCreating(true);
      timelines.createTimeline
        .mutateAsync('Main timeline')
        .then(async (created) => {
          await update('project', { lastTimelineId: created.id });
          onSelect(created.id);
        })
        .catch(() => {
          setAutoCreating(false);
        });
    }
  }, [timelines.isLoading, timelines.data, selectedProjectId, userId, autoCreating, timelines.createTimeline, update, onSelect]);

  if (!selectedProjectId) {
    return (
      <Card className="mx-auto max-w-2xl">
        <CardHeader>
          <CardTitle>No project selected</CardTitle>
          <CardDescription>Select a project in the header to manage timelines.</CardDescription>
        </CardHeader>
      </Card>
    );
  }

  return (
    <div className="mx-auto flex w-full max-w-4xl flex-col gap-4 p-6">
      <Card>
        <CardHeader>
          <CardTitle>Video editor timelines</CardTitle>
          <CardDescription>Pick a timeline or create a new one for this project.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex gap-2">
            <Input value={newName} onChange={(event) => setNewName(event.target.value)} placeholder="Timeline name" />
            <Button
              type="button"
              onClick={async () => {
                const created = await timelines.createTimeline.mutateAsync(newName || 'Untitled timeline');
                await update('project', { lastTimelineId: created.id });
                onSelect(created.id);
              }}
              disabled={timelines.createTimeline.isPending}
            >
              <Plus className="mr-1 h-4 w-4" />
              Create timeline
            </Button>
          </div>

          <div className="grid gap-3">
            {timelines.isLoading && Array.from({ length: 3 }).map((_, index) => <Skeleton key={index} className="h-20 w-full" />)}
            {(timelines.data ?? []).map((timeline) => {
              const isEditing = editingId === timeline.id;
              const isActive = settings?.lastTimelineId === timeline.id;

              return (
                <div key={timeline.id} className="flex items-center gap-3 rounded-xl border border-zinc-800 bg-zinc-950/70 p-4">
                  <div className="flex h-12 w-12 items-center justify-center rounded-lg bg-zinc-900 text-zinc-300">
                    <Clapperboard className="h-5 w-5" />
                  </div>
                  <div className="min-w-0 flex-1">
                    {isEditing ? (
                      <Input value={editingName} onChange={(event) => setEditingName(event.target.value)} />
                    ) : (
                      <div className="truncate text-sm font-medium text-zinc-100">{timeline.name}</div>
                    )}
                    <div className="mt-1 text-[11px] uppercase tracking-[0.16em] text-zinc-500">
                      Updated {new Date(timeline.updated_at).toLocaleString()}
                      {isActive ? ' · Last opened' : ''}
                    </div>
                  </div>
                  <div className="flex gap-2">
                    {isEditing ? (
                      <Button
                        type="button"
                        size="sm"
                        onClick={async () => {
                          await timelines.renameTimeline.mutateAsync({ timelineId: timeline.id, name: editingName || timeline.name });
                          setEditingId(null);
                        }}
                      >
                        Save
                      </Button>
                    ) : (
                      <Button
                        type="button"
                        size="sm"
                        variant="outline"
                        onClick={() => {
                          setEditingId(timeline.id);
                          setEditingName(timeline.name);
                        }}
                      >
                        <Pencil className="mr-1 h-3.5 w-3.5" />
                        Rename
                      </Button>
                    )}
                    <Button
                      type="button"
                      size="sm"
                      variant="outline"
                      onClick={async () => {
                        await update('project', { lastTimelineId: timeline.id });
                        onSelect(timeline.id);
                      }}
                    >
                      Open
                    </Button>
                    <Button
                      type="button"
                      size="icon"
                      variant="ghost"
                      className="text-red-300"
                      onClick={async () => {
                        await timelines.deleteTimeline.mutateAsync(timeline.id);
                        if (settings?.lastTimelineId === timeline.id) {
                          await update('project', { lastTimelineId: undefined });
                        }
                        toast.success('Timeline deleted');
                      }}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              );
            })}
            {!timelines.isLoading && (timelines.data?.length ?? 0) === 0 && (
              <div className="rounded-xl border border-dashed border-zinc-800 p-10 text-center">
                <div className="text-sm font-medium text-zinc-100">No timelines yet</div>
                <div className="mt-1 text-xs text-zinc-400">Create the first timeline to open the standalone editor.</div>
              </div>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

export default function VideoEditorPage() {
  const { selectedProjectId } = useProjectSelectionContext();
  const { userId } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();
  const timelineId = searchParams.get('timeline');
  const provider = useMemo(() => {
    if (!selectedProjectId || !userId) {
      return null;
    }
    return new SupabaseDataProvider({ projectId: selectedProjectId, userId });
  }, [selectedProjectId, userId]);
  const { update } = useToolSettings(videoEditorSettings.id, {
    projectId: selectedProjectId ?? undefined,
    enabled: Boolean(selectedProjectId),
  });

  useEffect(() => {
    if (!timelineId || !selectedProjectId) {
      return;
    }

    void update('project', { lastTimelineId: timelineId });
  }, [selectedProjectId, timelineId, update]);

  if (!timelineId || !provider || !userId) {
    return (
      <TimelineList
        onSelect={(nextTimelineId) => {
          setSearchParams({ timeline: nextTimelineId });
        }}
      />
    );
  }

  return (
    <VideoEditorProvider dataProvider={provider} timelineId={timelineId} userId={userId}>
      <VideoEditorShell
        mode="full"
        timelineId={timelineId}
        onCreateTimeline={() => navigate('/tools/video-editor')}
      />
    </VideoEditorProvider>
  );
}

import { useMemo, useRef } from 'react';
import { Film, ImageIcon, Music2, Upload } from 'lucide-react';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { ScrollArea } from '@/shared/components/ui/scroll-area';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { AssetRegistryEntry } from '@/tools/video-editor/types';

interface AssetPanelProps {
  assetMap: Record<string, string>;
  rows: Array<{ id: string; actions: Array<{ id: string }> }>;
  meta: Record<string, ClipMeta>;
  backgroundAsset?: string;
  showAll: boolean;
  showHidden: boolean;
  hidden: string[];
  setPanelState: (patch: { showAll?: boolean; showHidden?: boolean; hidden?: string[] }) => void;
  onUploadFiles: (files: File[]) => Promise<void>;
  registry?: Record<string, AssetRegistryEntry>;
}

const inferKind = (entry: AssetRegistryEntry | undefined, assetKey: string): 'visual' | 'audio' => {
  if (entry?.type?.startsWith('audio')) {
    return 'audio';
  }

  if (/\.(mp3|wav|aac|m4a)$/i.test(assetKey) || entry?.type?.startsWith('audio')) {
    return 'audio';
  }

  return 'visual';
};

export default function AssetPanel({
  assetMap,
  rows,
  meta,
  backgroundAsset,
  showAll,
  showHidden,
  hidden,
  setPanelState,
  onUploadFiles,
  registry,
}: AssetPanelProps) {
  const fileInputRef = useRef<HTMLInputElement | null>(null);

  const usedAssets = useMemo(() => {
    const used = new Set<string>();
    rows.forEach((row) => {
      row.actions.forEach((action) => {
        const assetKey = meta[action.id]?.asset;
        if (assetKey) {
          used.add(assetKey);
        }
      });
    });

    if (backgroundAsset) {
      used.add(backgroundAsset);
    }
    return used;
  }, [backgroundAsset, meta, rows]);

  const visibleAssets = useMemo(() => {
    return Object.entries(assetMap).filter(([assetKey]) => {
      if (!showAll && !usedAssets.has(assetKey)) {
        return false;
      }

      if (!showHidden && hidden.includes(assetKey)) {
        return false;
      }

      return true;
    });
  }, [assetMap, hidden, showAll, showHidden, usedAssets]);

  return (
    <div className="space-y-3 py-2">
      <div className="rounded-lg border border-dashed border-zinc-700 bg-zinc-900/70 p-3">
        <div className="flex items-center justify-between gap-2">
          <div>
            <div className="text-xs font-medium text-zinc-100">Upload assets</div>
            <div className="text-[11px] text-zinc-400">Videos, audio, and images land in the private timeline bucket.</div>
          </div>
          <Button
            type="button"
            size="sm"
            className="gap-1"
            onClick={() => fileInputRef.current?.click()}
          >
            <Upload className="h-3.5 w-3.5" />
            Upload
          </Button>
        </div>
        <Input
          ref={fileInputRef}
          type="file"
          multiple
          className="hidden"
          onChange={(event) => {
            const files = Array.from(event.target.files ?? []);
            if (files.length === 0) {
              return;
            }

            void onUploadFiles(files);
            event.target.value = '';
          }}
        />
      </div>

      <div className="flex items-center gap-2 text-[11px] text-zinc-400">
        <label className="inline-flex items-center gap-1">
          <input type="checkbox" checked={showAll} onChange={(event) => setPanelState({ showAll: event.target.checked })} />
          Show all
        </label>
        <label className="inline-flex items-center gap-1">
          <input type="checkbox" checked={showHidden} onChange={(event) => setPanelState({ showHidden: event.target.checked })} />
          Show hidden
        </label>
      </div>

      <ScrollArea className="h-[260px] rounded-lg border border-zinc-800">
        <div className="space-y-1 p-2">
          {visibleAssets.map(([assetKey, file]) => {
            const entry = registry?.[assetKey];
            const kind = inferKind(entry, file);
            const isUsed = usedAssets.has(assetKey);
            const isHidden = hidden.includes(assetKey);
            const icon = kind === 'audio'
              ? <Music2 className="h-3.5 w-3.5" />
              : entry?.type?.startsWith('image')
                ? <ImageIcon className="h-3.5 w-3.5" />
                : <Film className="h-3.5 w-3.5" />;

            return (
              <div
                key={assetKey}
                className="flex items-center gap-2 rounded-md border border-zinc-800 bg-zinc-900/60 px-2 py-2 text-xs text-zinc-200"
                draggable
                onDragStart={(event) => {
                  event.dataTransfer.setData('asset-key', assetKey);
                  event.dataTransfer.setData('asset-kind', kind);
                }}
              >
                <div className="flex h-8 w-8 items-center justify-center rounded bg-zinc-800 text-zinc-300">
                  {icon}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="truncate">{file.split('/').pop() ?? file}</div>
                  <div className="mt-0.5 text-[10px] text-zinc-500">
                    {isUsed ? 'In timeline' : 'Not used'}{isHidden ? ' · Hidden' : ''}
                  </div>
                </div>
                <Button
                  type="button"
                  variant="ghost"
                  size="sm"
                  className="h-7 px-2 text-[10px]"
                  onClick={() => {
                    const nextHidden = isHidden
                      ? hidden.filter((value) => value !== assetKey)
                      : [...hidden, assetKey];
                    setPanelState({ hidden: nextHidden });
                  }}
                >
                  {isHidden ? 'Show' : 'Hide'}
                </Button>
              </div>
            );
          })}
          {visibleAssets.length === 0 && (
            <div className="rounded-md border border-dashed border-zinc-800 p-4 text-center text-xs text-zinc-500">
              No assets match the current filters.
            </div>
          )}
        </div>
      </ScrollArea>
    </div>
  );
}

import { memo, useEffect, useRef, useState } from 'react';
import { ChevronDown, ChevronRight } from 'lucide-react';
import AssetPanel from '@/tools/video-editor/components/PropertiesPanel/AssetPanel';
import { ClipPanel } from '@/tools/video-editor/components/PropertiesPanel/ClipPanel';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';

function PropertiesPanelComponent() {
  const {
    data,
    selectedClip,
    selectedTrack,
    selectedClipHasPredecessor,
    compositionSize,
    setSelectedClipId,
    handleDeleteClip,
    handleSelectedClipChange,
    handleResetClipPosition,
    handleSplitSelectedClip,
    handleToggleMute,
    preferences,
    setActiveClipTab,
    setAssetPanelState,
    uploadFiles,
  } = useTimelineEditorContext();
  const [assetsExpanded, setAssetsExpanded] = useState(true);
  const prevClipIdRef = useRef(selectedClip?.id);

  useEffect(() => {
    if (selectedClip && selectedClip.id !== prevClipIdRef.current && selectedClip.clipType === 'text') {
      setActiveClipTab('text');
    }
    prevClipIdRef.current = selectedClip?.id;
  }, [selectedClip, setActiveClipTab]);

  if (!data) {
    return null;
  }

  return (
    <div className="flex h-full min-h-0 flex-col gap-3">
      <div className="overflow-hidden rounded-xl border border-zinc-800 bg-zinc-950/80">
        <button
          type="button"
          className="flex w-full items-center gap-1.5 px-3 py-2 text-[11px] font-semibold uppercase tracking-[0.16em] text-zinc-400 hover:text-zinc-100"
          onClick={() => setAssetsExpanded((value) => !value)}
        >
          {assetsExpanded ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />}
          Assets
        </button>
        {assetsExpanded && (
          <div className="border-t border-zinc-800 px-3 pb-3">
            <AssetPanel
              assetMap={data.assetMap}
              rows={data.rows}
              meta={data.meta}
              backgroundAsset={data.output.background ?? undefined}
              showAll={preferences.assetPanel.showAll}
              showHidden={preferences.assetPanel.showHidden}
              hidden={preferences.assetPanel.hidden}
              setPanelState={setAssetPanelState}
              onUploadFiles={uploadFiles}
              registry={data.registry.assets}
            />
          </div>
        )}
      </div>
      <div className="min-h-0 flex-1 overflow-auto rounded-xl border border-zinc-800 bg-zinc-950/80 p-3">
        <ClipPanel
          clip={selectedClip}
          track={selectedTrack}
          hasPredecessor={selectedClipHasPredecessor}
          onChange={handleSelectedClipChange}
          onResetPosition={handleResetClipPosition}
          onClose={() => setSelectedClipId(null)}
          onDelete={selectedClip ? () => handleDeleteClip(selectedClip.id) : undefined}
          onSplit={handleSplitSelectedClip}
          onToggleMute={handleToggleMute}
          compositionWidth={compositionSize.width}
          compositionHeight={compositionSize.height}
          activeTab={preferences.activeClipTab}
          setActiveTab={setActiveClipTab}
        />
      </div>
    </div>
  );
}

export const PropertiesPanel = memo(PropertiesPanelComponent);

import type { AssetRegistry, AssetRegistryEntry, TimelineConfig } from '@/tools/video-editor/types';

