/**
 * Loose type for objects that might have generation_id and/or id.
 * Use this when dealing with untyped or loosely-typed media objects.
 */
import type { GenerationRow } from '@/domains/generation/types';

interface MaybeHasGenerationId {
  generation_id?: string | null;
  id?: string | null;
  metadata?: Record<string, unknown>;
}

const NON_PRELOADABLE_URL_MARKERS = ['_joined_frame.jpg'] as const;

/**
 * Get the canonical generation ID from a media item.
 * Handles both direct generations (id) and variants (generation_id).
 * Also checks metadata.generation_id for compatibility with various data shapes.
 *
 * Priority: generation_id > metadata.generation_id > id
 *
 * @example
 * // Instead of: (media as unknown).generation_id || media.id
 * const genId = getGenerationId(media);
 */
export function getGenerationId(
  media: MaybeHasGenerationId | null | undefined
): string | null {
  if (!media) return null;
  const metadataGenerationId = typeof media.metadata?.generation_id === 'string'
    ? media.metadata.generation_id
    : null;
  return media.generation_id || metadataGenerationId || media.id || null;
}

/**
 * Centralized preload eligibility contract for URL-based media entries.
 */
export function isPreloadableMediaUrl(url: string | null | undefined): boolean {
  if (!url) {
    return false;
  }

  return !NON_PRELOADABLE_URL_MARKERS.some((marker) => url.includes(marker));
}

/**
 * Media item with various URL properties (normalized across sources)
 */
interface MediaWithUrls {
  location?: string | null;
  url?: string | null;
  thumbnail_url?: string | null;
  thumbUrl?: string | null;
  imageUrl?: string | null;
}

export function getMediaUrl(media: MediaWithUrls | null | undefined): string | undefined {
  if (!media) return undefined;
  return media.location || media.url || media.imageUrl || undefined;
}

export function getThumbnailUrl(media: MediaWithUrls | null | undefined): string | undefined {
  if (!media) return undefined;
  return media.thumbnail_url || media.thumbUrl || undefined;
}

/** Transform a variant to a GenerationRow shape for lightbox display. */
export function variantToGenerationRow(
  media: {
    id: string;
    url: string;
    thumbUrl?: string;
    createdAt?: string;
    starred?: boolean;
    metadata?: { prompt?: string; tool_type?: string; variant_type?: string; generation_id?: string | null };
    generation_id?: string | null;
  },
  mediaType: 'video' | 'image',
): GenerationRow {
  const generationId = getGenerationId(media) ?? media.id;

  return {
    id: media.id,
    generation_id: generationId,
    location: media.url,
    thumbUrl: media.thumbUrl,
    type: mediaType,
    createdAt: media.createdAt,
    params: {
      prompt: media.metadata?.prompt,
      tool_type: media.metadata?.tool_type,
      variant_type: media.metadata?.variant_type,
      variant_id: media.id,
    },
    starred: media.starred ?? false,
  };
}

import React from 'react';
import type { GenerationRow } from '@/domains/generation/types';
import { isVideoAny } from '@/shared/lib/typeGuards';
import type {
  AdjacentSegmentsData,
  SegmentSlotModeData,
  TaskDetailsData,
  LightboxNavigationProps,
  LightboxShotWorkflowProps,
  LightboxFeatureFlags,
  LightboxActionHandlers,
  VideoLightboxVideoProps,
} from './types';
import { ImageLightbox } from './ImageLightbox';
import { VideoLightbox } from './VideoLightbox';

interface MediaLightboxCoreProps {
  media?: GenerationRow;
  parentGenerationIdOverride?: string;
  onClose: () => void;
  segmentSlotMode?: SegmentSlotModeData;
  readOnly?: boolean;
  toolTypeOverride?: string;
  onNavigateToGeneration?: (generationId: string) => void;
  onOpenExternalGeneration?: (generationId: string, derivedContext?: string[]) => Promise<void>;
  shotId?: string;
  tasksPaneOpen?: boolean;
  tasksPaneWidth?: number;
  initialVariantId?: string;
  adjacentSegments?: AdjacentSegmentsData;
}

interface MediaLightboxBehaviorProps {
  navigation?: LightboxNavigationProps;
  shotWorkflow?: LightboxShotWorkflowProps;
  features?: LightboxFeatureFlags;
  actions?: LightboxActionHandlers;
  videoProps?: VideoLightboxVideoProps;
}

interface MediaLightboxTaskDetailsProps {
  taskDetailsData?: TaskDetailsData;
}

interface MediaLightboxTickStateProps {
  showTickForImageId?: string | null;
  showTickForSecondaryImageId?: string | null;
}

export type MediaLightboxProps =
  & MediaLightboxCoreProps
  & MediaLightboxBehaviorProps
  & MediaLightboxTaskDetailsProps
  & MediaLightboxTickStateProps;

export const MediaLightbox: React.FC<MediaLightboxProps> = (props) => {
  const {
    media,
    segmentSlotMode,
    navigation,
    shotWorkflow,
    features,
    actions,
    videoProps,
  } = props;

  const sharedContainerProps = {
    onClose: props.onClose,
    readOnly: props.readOnly,
    shotId: props.shotId,
    initialVariantId: props.initialVariantId,
    taskDetailsData: props.taskDetailsData,
    onOpenExternalGeneration: props.onOpenExternalGeneration,
    showTickForImageId: props.showTickForImageId,
    showTickForSecondaryImageId: props.showTickForSecondaryImageId,
    tasksPaneOpen: props.tasksPaneOpen,
    tasksPaneWidth: props.tasksPaneWidth,
    adjacentSegments: props.adjacentSegments,
    navigation,
    shotWorkflow,
    features,
    actions,
  };

  if (segmentSlotMode) {
    return (
      <VideoLightbox
        {...sharedContainerProps}
        media={media}
        segmentSlotMode={segmentSlotMode}
        parentGenerationIdOverride={props.parentGenerationIdOverride}
        videoProps={videoProps}
      />
    );
  }

  if (!media) {
    return null;
  }

  if (isVideoAny(media)) {
    return (
      <VideoLightbox
        {...sharedContainerProps}
        media={media}
        segmentSlotMode={segmentSlotMode}
        parentGenerationIdOverride={props.parentGenerationIdOverride}
        videoProps={videoProps}
      />
    );
  }

  return (
    <ImageLightbox
      {...sharedContainerProps}
      media={media}
      toolTypeOverride={props.toolTypeOverride}
      onNavigateToGeneration={props.onNavigateToGeneration}
    />
  );
};

/**
 * useVariants Hook
 *
 * Centralized hook for fetching and managing variants for a generation.
 * Allows switching between variants and setting the primary variant.
 * Supports realtime updates via RealtimeProvider.
 *
 * Used by: MediaLightbox, InlineEditView, and other components that display variants.
 */

import { useState, useCallback, useMemo, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { coerceVariantType, VARIANT_TYPE, type VariantType } from '@/shared/constants/variantTypes';
import { enqueueVariantInvalidation } from '@/shared/hooks/invalidation/useGenerationInvalidation';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { generationQueryKeys } from '@/shared/lib/queryKeys/generations';
import { useAppEventListener } from '@/shared/lib/typedEvents';

/**
 * A variant of a generation (from generation_variants table)
 */
export interface GenerationVariant {
  id: string;
  generation_id: string;
  location: string;
  thumbnail_url: string | null;
  params: Record<string, unknown> | null;
  is_primary: boolean;
  starred: boolean;
  variant_type: VariantType | null;
  name: string | null;
  created_at: string;
  viewed_at: string | null;
}

/**
 * Return type for useVariants hook
 */
interface UseVariantsReturn {
  variants: GenerationVariant[];
  primaryVariant: GenerationVariant | null;
  activeVariant: GenerationVariant | null;
  isLoading: boolean;
  error: Error | null;
  refetch: () => void;
  setActiveVariantId: (variantId: string | null) => void;
  setPrimaryVariant: (variantId: string) => Promise<void>;
  deleteVariant: (variantId: string) => Promise<void>;
}

interface UseVariantsProps {
  generationId: string | null;
  enabled?: boolean;
}

export const useVariants = ({
  generationId,
  enabled = true,
}: UseVariantsProps): UseVariantsReturn => {
  const queryClient = useQueryClient();
  const [activeVariantId, setActiveVariantIdInternal] = useState<string | null>(null);

  // Stable callback - no deps needed since we just forward to internal setter
  const setActiveVariantId = useCallback((variantId: string | null) => {
    setActiveVariantIdInternal(variantId);
  }, []);

  // Fetch variants for this generation
  const {
    data: variants = [],
    isLoading,
    error,
    refetch,
  } = useQuery({
    queryKey: generationId ? generationQueryKeys.variants(generationId) : ['generation-variants', null],
    queryFn: async () => {
      if (!generationId) return [];

      const { data, error } = await supabase().from('generation_variants')
        .select('*')
        .eq('generation_id', generationId)
        .order('created_at', { ascending: false });

      if (error) {
        console.error('[useVariants] Error fetching variants:', error);
        throw error;
      }

      return (data || []).map((variant) => ({
        ...variant,
        variant_type: coerceVariantType(variant.variant_type),
      })) as GenerationVariant[];
    },
    enabled: enabled && !!generationId,
    staleTime: 30000, // 30 seconds
  });

  // Listen for realtime variant changes and refetch when our generationId is affected
  const handleVariantChange = useCallback((detail: { affectedGenerationIds: string[] }) => {
    if (!generationId || !enabled) return;
    const affectedIds = detail?.affectedGenerationIds || [];
    if (affectedIds.includes(generationId)) {
      refetch();
    }
  }, [generationId, enabled, refetch]);

  useAppEventListener('realtime:variant-change-batch', handleVariantChange);

  // Find the primary variant
  const primaryVariant = useMemo(() => {
    return variants.find((v) => v.is_primary) || null;
  }, [variants]);

  // Get the active variant (selected or primary, fallback to first variant)
  const activeVariant = useMemo(() => {
    if (activeVariantId) {
      const found = variants.find((v) => v.id === activeVariantId);
      if (found) {
        return found;
      }
    }
    // Fall back to primary, then first variant if no primary exists
    return primaryVariant || variants[0] || null;
  }, [variants, activeVariantId, primaryVariant]);

  // Initialize active variant to primary (or first variant) when variants load
  // NOTE: Using useEffect, not useMemo - side effects should not be in useMemo
  useEffect(() => {
    if (!activeVariantId && variants.length > 0) {
      const variantToSelect = primaryVariant || variants[0];
      if (variantToSelect) {
        setActiveVariantIdInternal(variantToSelect.id);
      }
    }
  }, [primaryVariant, variants, activeVariantId]);

  // Mutation to set a variant as primary
  const setPrimaryMutation = useMutation({
    mutationFn: async (variantId: string) => {

      // Update the variant to be primary
      // The database trigger will handle unsetting the old primary
      const { error } = await supabase().from('generation_variants')
        .update({ is_primary: true })
        .eq('id', variantId);

      if (error) {
        console.error('[useVariants] Error setting primary variant:', error);
        throw error;
      }

      return variantId;
    },
    onSuccess: async (variantId) => {

      // Invalidate caches using centralized function
      if (generationId) {
        await enqueueVariantInvalidation(queryClient, {
          generationId,
          reason: 'set-primary-variant',
        });
      }

      // SINGLE-SEGMENT PROPAGATION: If this is a child of a single-segment parent,
      // also create a variant on the parent so the main generation updates
      try {
        // Get the promoted variant's location and thumbnail
        const { data: promotedVariant } = await supabase().from('generation_variants')
          .select('location, thumbnail_url, params')
          .eq('id', variantId)
          .single();

        if (!promotedVariant || !generationId) return;

        // Check if this generation is a child with a parent
        const { data: generation } = await supabase().from('generations')
          .select('is_child, parent_generation_id')
          .eq('id', generationId)
          .single();

        if (!generation?.is_child || !generation?.parent_generation_id) return;

        // Count how many children the parent has
        const { count: childCount } = await supabase().from('generations')
          .select('id', { count: 'exact', head: true })
          .eq('parent_generation_id', generation.parent_generation_id)
          .eq('is_child', true);

        // Only propagate for single-segment parents
        if (childCount !== 1) {
          return;
        }

        // Create a new variant on the parent with the promoted video
        // Exclude task-specific fields that shouldn't propagate to parent
        const {
          source_task_id: _sourceTaskId,
          child_generation_id: _childGenId,
          ...paramsToPropagate
        } = (promotedVariant.params || {}) as Record<string, unknown>;

        const { error: insertError } = await supabase().from('generation_variants')
          .insert({
            generation_id: generation.parent_generation_id,
            location: promotedVariant.location,
            thumbnail_url: promotedVariant.thumbnail_url,
            is_primary: true, // DB trigger will unset old primary
            variant_type: VARIANT_TYPE.TRAVEL_SEGMENT,
            params: {
              ...paramsToPropagate,
              propagated_from_child: generationId,
              propagated_from_variant: variantId,
            },
          });

        if (insertError) {
          normalizeAndPresentError(insertError, { context: 'useVariants', showToast: false });
        } else {
          // Invalidate parent's variant cache
          await enqueueVariantInvalidation(queryClient, {
            generationId: generation.parent_generation_id,
            reason: 'single-segment-propagation',
          });
        }
      } catch (err) {
        console.error('[useVariants] Error in single-segment propagation:', err);
        // Don't throw - this is a nice-to-have, not critical
      }
    },
    onError: (error) => {
      normalizeAndPresentError(error, { context: 'useVariants.setPrimaryVariant', toastTitle: 'Failed to set primary variant' });
    },
  });

  const setPrimaryVariant = useCallback(
    async (variantId: string) => {
      await setPrimaryMutation.mutateAsync(variantId);
    },
    [setPrimaryMutation]
  );

  // Mutation to delete a variant
  const deleteVariantMutation = useMutation({
    mutationFn: async (variantId: string) => {

      // Check if variant is primary - don't allow deleting primary
      const variant = variants.find(v => v.id === variantId);
      if (variant?.is_primary) {
        throw new Error('Cannot delete the primary variant');
      }

      const { error } = await supabase().from('generation_variants')
        .delete()
        .eq('id', variantId);

      if (error) {
        console.error('[useVariants] Error deleting variant:', error);
        throw error;
      }

/**
 * useLoadVariantImages Hook
 *
 * Loads a variant's source images onto the timeline by switching primary variants.
 * For each image position (start, end) where the image differs:
 * - Same generation, different variant → find and set as primary
 * - Same generation, match by URL → find and set as primary
 * - Different generation entirely → create new variant with source URL, set as primary
 */

import { useCallback, useRef, useEffect } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { enqueueVariantInvalidation } from '@/shared/hooks/invalidation/useGenerationInvalidation';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import type { GenerationVariant } from '@/shared/hooks/variants/useVariants';
import type { CurrentSegmentImagesData } from '@/shared/components/VariantSelector/variantSourceImages';

interface UseLoadVariantImagesProps {
  currentSegmentImages?: CurrentSegmentImagesData & {
    startShotGenerationId?: string;
    endShotGenerationId?: string;
  };
}

function throwWithContext(message: string, cause: unknown): never {
  const error = new Error(message);
  (error as Error & { cause?: unknown }).cause = cause;
  throw error;
}

/**
 * Extract the storage path from a full URL or relative path for matching.
 */
function extractStoragePath(url: string | undefined | null): string | null {
  if (!url) return null;
  const storageMatch = url.match(/\/storage\/v1\/object\/(?:public|sign)\/(.+?)(?:\?|$)/);
  if (storageMatch) return storageMatch[1];
  if (url.startsWith('generations/') || url.startsWith('/generations/')) {
    return url.replace(/^\//, '');
  }
  return url;
}

function pathsMatch(url1: string | undefined | null, url2: string | undefined | null): boolean {
  if (!url1 || !url2) return false;
  if (url1 === url2) return true;
  const p1 = extractStoragePath(url1);
  const p2 = extractStoragePath(url2);
  return !!p1 && !!p2 && p1 === p2;
}

export function useLoadVariantImages({ currentSegmentImages }: UseLoadVariantImagesProps) {
  const queryClient = useQueryClient();
  const abortControllerRef = useRef<AbortController | null>(null);

  // Clean up on unmount
  useEffect(() => {
    return () => {
      abortControllerRef.current?.abort();
    };
  }, []);

  const loadVariantImages = useCallback(async (variant: GenerationVariant) => {
    // Abort any previous in-flight request
    abortControllerRef.current?.abort();
    abortControllerRef.current = new AbortController();
    const signal = abortControllerRef.current.signal;

    if (!currentSegmentImages) return;

    const params = variant.params;
    if (!params) return;

    // Extract source image data from variant params
    const indivParams = (params.individual_segment_params || {}) as Record<string, unknown>;
    const resolvedPaths = (indivParams.input_image_paths_resolved || params.input_image_paths_resolved) as string[] | undefined;

    const variantStartGenId = (indivParams.start_image_generation_id || params.start_image_generation_id) as string | undefined;
    const variantEndGenId = (indivParams.end_image_generation_id || params.end_image_generation_id) as string | undefined;
    const variantStartVariantId = (indivParams.start_image_variant_id || params.start_image_variant_id) as string | undefined;
    const variantEndVariantId = (indivParams.end_image_variant_id || params.end_image_variant_id) as string | undefined;
    const variantStartUrl = resolvedPaths?.[0] || (indivParams.start_image_url || params.start_image_url) as string | undefined;
    const variantEndUrl = resolvedPaths && resolvedPaths.length > 1
      ? resolvedPaths[resolvedPaths.length - 1]
      : (indivParams.end_image_url || params.end_image_url) as string | undefined;

    // Process each image position
    const positions = [
      {
        variantGenId: variantStartGenId,
        variantVariantId: variantStartVariantId,
        variantUrl: variantStartUrl,
        currentGenId: currentSegmentImages.startGenerationId,
        currentVariantId: currentSegmentImages.startVariantId,
        currentUrl: currentSegmentImages.startUrl,
      },
      {
        variantGenId: variantEndGenId,
        variantVariantId: variantEndVariantId,
        variantUrl: variantEndUrl,
        currentGenId: currentSegmentImages.endGenerationId,
        currentVariantId: currentSegmentImages.endVariantId,
        currentUrl: currentSegmentImages.endUrl,
      },
    ];

    for (const pos of positions) {
      // Skip if no source data or no current data
      if (!pos.variantGenId && !pos.variantUrl) continue;
      if (!pos.currentGenId) continue;

      // Check if this request was superseded before each async operation
      if (signal.aborted) return;

      try {
        await loadSingleImage({
          variantGenId: pos.variantGenId,
          variantVariantId: pos.variantVariantId,
          variantUrl: pos.variantUrl,
          currentGenId: pos.currentGenId,
          currentVariantId: pos.currentVariantId,
          currentUrl: pos.currentUrl,
        });

        if (signal.aborted) return;

        // Invalidate caches for this generation
        await enqueueVariantInvalidation(queryClient, {
          generationId: pos.currentGenId,
          reason: 'load-variant-images',
        });

        if (signal.aborted) return;
      } catch (error) {
        if (signal.aborted) return;
        normalizeAndPresentError(error, { context: 'LoadVariantImages', showToast: false });
      }
    }
  }, [currentSegmentImages, queryClient]);

  return { loadVariantImages };
}

/**
 * Load a single image position: find or create the variant and make it primary.
 */
async function loadSingleImage(pos: {
  variantGenId: string | undefined;
  variantVariantId: string | undefined;
  variantUrl: string | undefined;
  currentGenId: string;
  currentVariantId: string | undefined;
  currentUrl: string | undefined;
}) {
  // Check if images actually differ
  if (pos.variantGenId === pos.currentGenId) {
    if (pos.variantVariantId && pos.currentVariantId && pos.variantVariantId === pos.currentVariantId) {
      return; // Same variant, nothing to do
    }
    if (!pos.variantVariantId && !pos.currentVariantId) {
      if (pathsMatch(pos.variantUrl, pos.currentUrl)) return;
    }
  }

  const targetGenerationId = pos.currentGenId;

  // Strategy 1: Same generation - find variant by ID
  if (pos.variantGenId === pos.currentGenId && pos.variantVariantId) {
    await setPrimaryById(pos.variantVariantId);
    return;
  }

  // Strategy 2: Find variant by URL match on the current generation
  if (pos.variantUrl) {
    const { data: existingVariants } = await supabase().from('generation_variants')
      .select('id, location')
      .eq('generation_id', targetGenerationId);

    if (existingVariants) {
      const match = existingVariants.find(v => pathsMatch(v.location, pos.variantUrl));
      if (match) {
        await setPrimaryById(match.id);
        return;
      }
    }

    // Strategy 3: Create new variant with the source URL
    const { error } = await supabase().from('generation_variants')
      .insert({
        generation_id: targetGenerationId,
        location: pos.variantUrl,
        thumbnail_url: pos.variantUrl,
        is_primary: true, // DB trigger handles unsetting old primary
        variant_type: 'loaded',
        params: {
          source_generation_id: pos.variantGenId,
          loaded_from_variant: pos.variantVariantId,
          source_url: pos.variantUrl,
        },
      })
      .select('id')
      .single();

    if (error) {
      throwWithContext(`Failed to create variant: ${error.message}`, error);
    }
  }
}

/**
 * Set a variant as primary by ID. DB trigger handles unsetting the old primary.
 */
async function setPrimaryById(variantId: string) {
  const { error } = await supabase().from('generation_variants')
    .update({ is_primary: true })
    .eq('id', variantId);

  if (error) {
    throwWithContext(`Failed to set primary variant: ${error.message}`, error);
  }
}

