    reloadFromServer: dataHook.reloadFromServer,
    startRender: dataHook.startRender,
  }), [
    dataHook.reloadFromServer,
    dataHook.renderDirty,
    dataHook.renderLog,
    dataHook.renderProgress,
    dataHook.renderStatus,
    dataHook.saveStatus,
    dataHook.setScaleWidth,
    dataHook.startRender,
    editing.handleAddText,
    trackManagement.handleAddTrack,
    trackManagement.handleClearUnusedTracks,
    trackManagement.unusedTrackCount,
  ]);

  const playbackValue = useMemo<TimelinePlaybackContextValue>(() => ({
    currentTime: playback.currentTime,
    previewRef: playback.previewRef,
    playerContainerRef: playback.playerContainerRef,
    onPreviewTimeUpdate: playback.onPreviewTimeUpdate,
    formatTime: playback.formatTime,
  }), [
    playback.currentTime,
    playback.formatTime,
    playback.onPreviewTimeUpdate,
    playback.playerContainerRef,
    playback.previewRef,
  ]);

  return {
    editor,
    chrome,
    playback: playbackValue,
  };
}

import { createContext, useContext } from 'react';
import type { TimelineEditorContextValue } from '@/tools/video-editor/hooks/useTimelineState';

const TimelineEditorContext = createContext<TimelineEditorContextValue | null>(null);

export function TimelineEditorContextProvider({
  value,
  children,
}: {
  value: TimelineEditorContextValue;
  children: React.ReactNode;
}) {
  return (
    <TimelineEditorContext.Provider value={value}>
      {children}
    </TimelineEditorContext.Provider>
  );
}

export function useTimelineEditorContext(): TimelineEditorContextValue {
  const context = useContext(TimelineEditorContext);
  if (!context) {
    throw new Error('useTimelineEditorContext must be used within TimelineEditorContextProvider');
  }

  return context;
}

