function PreviewPanelComponent() {
  const {
    data,
    resolvedConfig,
    trackScaleMap,
    compositionSize,
    selectedClipId,
    setSelectedClipId,
    onOverlayChange,
  } = useTimelineEditorContext();
  const {
    previewRef,
    playerContainerRef,
    currentTime,
    onPreviewTimeUpdate,
  } = useTimelinePlaybackContext();

  if (!data || !resolvedConfig) {
    return null;
  }

  return (
    <div className="flex h-full min-h-0 flex-col overflow-hidden rounded-xl border border-zinc-800 bg-zinc-950">
      <div className="relative flex min-h-0 flex-1">
        <div
          className="relative flex min-h-0 flex-1 items-center justify-center overflow-hidden bg-zinc-950"
          onMouseDownCapture={(event) => {
            const target = event.target;
            if (!(target instanceof Element)) {
              return;
