function TimelineEditorComponent() {
  const {
    data,
    resolvedConfig,
    timelineRef,
    timelineWrapperRef,
    dataRef,
    moveClipToRow,
    createTrackAndMoveClip,
    setSelectedClipId,
    setSelectedTrackId,
    crossTrackActive,
    scale,
    scaleWidth,
    actionDragStateRef,
    clearActionDragState,
    selectedClipId,
    selectedTrackId,
    handleTrackPopoverChange,
    handleReorderTrack,
    handleRemoveTrack,
    onChange,
    onCursorDrag,
    onClickTimeArea,
    onActionMoveStart,
    onActionMoving,
    onActionMoveEnd,
    onActionResizeStart,
    onActionResizeEnd,
    onTimelineDragOver,
    onTimelineDragLeave,
    onTimelineDrop,
  } = useTimelineEditorContext();

  useCrossTrackDrag({
    timelineWrapperRef,
    dataRef,
    moveClipToRow,
    createTrackAndMoveClip,
    setSelectedClipId,
    setSelectedTrackId,
    crossTrackActive,
    rowHeight: ROW_HEIGHT,
    scale,
    scaleWidth,
    startLeft: TIMELINE_START_LEFT,
    actionDragStateRef,
    clearActionDragState,
  });

  const scaleCount = useMemo(() => {
    if (!data) {
      return 1;
    }

    let maxEnd = 0;
    for (const row of data.rows) {
      for (const action of row.actions) {
        maxEnd = Math.max(maxEnd, action.end);
      }
    }

    return Math.ceil((maxEnd + 20) / scale) + 1;
  }, [data, scale]);

  const thumbnailMap = useMemo<Record<string, string>>(() => {
    if (!resolvedConfig) {
      return {};
    }

    return resolvedConfig.clips.reduce<Record<string, string>>((acc, clip) => {
      if (clip.clipType === 'text' || !clip.assetEntry?.type?.startsWith('image')) {
        return acc;
      }

      acc[clip.id] = clip.assetEntry.src;
      return acc;
    }, {});
  }, [resolvedConfig]);

  const handleClipSelect = useCallback((clipId: string, trackId: string) => {
    setSelectedClipId(clipId);
    setSelectedTrackId(trackId);
  }, [setSelectedClipId, setSelectedTrackId]);

  const pixelsPerSecond = scaleWidth / scale;
  const metaRef = useRef(data?.meta);
  const selectedClipIdRef = useRef(selectedClipId);
  const thumbnailMapRef = useRef(thumbnailMap);
  const pixelsPerSecondRef = useRef(pixelsPerSecond);

  metaRef.current = data?.meta;
  selectedClipIdRef.current = selectedClipId;
  thumbnailMapRef.current = thumbnailMap;
  pixelsPerSecondRef.current = pixelsPerSecond;

  const getActionRender = useCallback((action: TimelineAction) => {
    const clipMeta = metaRef.current?.[action.id];
    if (!clipMeta) {
      return null;
    }

    const clipWidthPx = (action.end - action.start) * pixelsPerSecondRef.current;
    const thumbnailSrc = clipWidthPx >= 40 ? thumbnailMapRef.current[action.id] : undefined;

    return (
      <ClipAction
        action={action}
        clipMeta={clipMeta}
        isSelected={selectedClipIdRef.current === action.id}
        thumbnailSrc={thumbnailSrc}
        onSelect={handleClipSelect}
      />
    );
  }, [handleClipSelect]);

  if (!data) {
    return null;
  }

  const kindCountMap = data.tracks.reduce<Record<string, number>>((counts, track) => {
    counts[track.kind] = (counts[track.kind] ?? 0) + 1;
    return counts;
  }, {});

  return (
    <div className="flex h-full overflow-hidden rounded-xl border border-zinc-800 bg-zinc-950">
      <div className="flex w-36 shrink-0 flex-col overflow-y-auto border-r border-zinc-800 pt-[30px]">
        {data.tracks.map((track, index) => (
          <TrackLabel
            key={track.id}
            track={track}
            isSelected={selectedTrackId === track.id}
            trackCount={data.tracks.length}
            trackIndex={index}
            sameKindCount={kindCountMap[track.kind] ?? 0}
            onSelect={setSelectedTrackId}
            onChange={handleTrackPopoverChange}
            onReorder={handleReorderTrack}
            onRemove={handleRemoveTrack}
          />
        ))}
      </div>
      <div
        ref={timelineWrapperRef}
        className="timeline-wrapper relative min-w-0 flex-1 overflow-hidden"
        onDragOver={onTimelineDragOver}
        onDragLeave={onTimelineDragLeave}
        onDrop={onTimelineDrop}
      >
        <Timeline
          ref={timelineRef}
          style={{ width: '100%', height: '100%' }}
          editorData={data.rows}
          effects={data.effects}
          onChange={onChange}
          scale={scale}
          scaleWidth={scaleWidth}
          minScaleCount={scaleCount}
          maxScaleCount={scaleCount}
          scaleSplitCount={5}
          startLeft={TIMELINE_START_LEFT}
          rowHeight={ROW_HEIGHT}
          autoScroll
          dragLine
          getActionRender={getActionRender}
          onCursorDrag={onCursorDrag}
          onClickTimeArea={onClickTimeArea}
          onActionMoveStart={onActionMoveStart}
          onActionMoving={onActionMoving}
          onActionMoveEnd={onActionMoveEnd}
          onActionResizeStart={onActionResizeStart}
          onActionResizeEnd={onActionResizeEnd}
        />
      </div>
    </div>
  );
}

