import { GenerationRow } from '@/domains/generation/types';

interface ShotGenerationRow {
  id: string;
  generation_id: string;
  timeline_frame: number;
}

interface JoinedGeneration {
  id: string;
  location: string | null;
  thumbnail_url: string | null;
  type: string | null;
  created_at: string;
  starred: boolean | null;
  name: string | null;
  based_on: string | null;
  params: unknown;
  primary_variant_id?: string | null;
  primary_variant?: {
    location: string | null;
    thumbnail_url: string | null;
  } | null;
}

interface RawShotGeneration {
  id: string;
  shot_id?: string;
  generation_id?: string;
  timeline_frame: number | null;
  metadata?: unknown;
  generations?: JoinedGeneration | null;
  generation?: JoinedGeneration | null;
}

function toRecord(value: unknown): Record<string, unknown> {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }
  return {};
}

/**
 * Maps a raw Supabase response from shot_generations (with joined generations)
 * to the standardized GenerationRow format used throughout the app.
 *
 * IMPORTANT: This must be used by ALL hooks (useListShots, useShotImages, etc.)
 * to ensure selectors and filters work consistently across the Sidebar and Editor.
 */
export const mapShotGenerationToRow = (sg: RawShotGeneration): GenerationRow | null => {
  const gen = sg.generations || sg.generation; // Handle both aliases
  if (!gen) return null;

  // CRITICAL: Use primary variant's location/thumbnail if available
  // Falls back to generation.location if no primary variant exists (legacy data)
  const primaryVariant = gen.primary_variant;
  const effectiveLocation = primaryVariant?.location || gen.location;
  const effectiveThumbnail = primaryVariant?.thumbnail_url || gen.thumbnail_url || effectiveLocation;

  return {
    id: sg.id, // shot_generations.id (unique per entry in shot)
    generation_id: gen.id, // generations.id (the actual generation)

    // Deprecated aliases (kept for backwards compat during transition)
    shotImageEntryId: sg.id,
    shot_generation_id: sg.id,

    location: effectiveLocation,
    imageUrl: effectiveLocation,
    thumbUrl: effectiveThumbnail,
    type: gen.type || 'image',
    created_at: gen.created_at,
    createdAt: gen.created_at,
    starred: gen.starred || false,
    name: gen.name,
    based_on: gen.based_on,
    params: toRecord(gen.params),

    timeline_frame: sg.timeline_frame,
    metadata: toRecord(sg.metadata),
    primary_variant_id: gen.primary_variant_id || null,

    position: sg.timeline_frame != null ? Math.floor(sg.timeline_frame / 50) : undefined,
  } as GenerationRow;
};

import type { RefObject } from 'react';
import { forwardRef, useEffect, useImperativeHandle, useMemo, useRef, useState } from 'react';
import { Pause, Play, SkipBack } from 'lucide-react';
import { Player, type PlayerRef } from '@remotion/player';
import { Button } from '@/shared/components/ui/button';
import { TimelineRenderer } from '@/tools/video-editor/compositions/TimelineRenderer';
import { getTimelineDurationInFrames, parseResolution } from '@/tools/video-editor/lib/config-utils';
import type { ResolvedTimelineConfig } from '@/tools/video-editor/types';

export interface PreviewHandle {
  seek: (time: number) => void;
  play: () => void;
  pause: () => void;
  togglePlayPause: () => void;
  readonly isPlaying: boolean;
}

interface RemotionPreviewProps {
  config: ResolvedTimelineConfig;
  onTimeUpdate: (time: number) => void;
  playerContainerRef: RefObject<HTMLDivElement | null>;
  compact?: boolean;
}

export const RemotionPreview = forwardRef<PreviewHandle, RemotionPreviewProps>(function RemotionPreview(
  { config, onTimeUpdate, playerContainerRef, compact = false },
  ref,
) {
  const playerRef = useRef<PlayerRef>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const inputProps = useMemo(() => ({ config }), [config]);
  const metadata = useMemo(() => {
    const fps = config.output.fps;
    const { width, height } = parseResolution(config.output.resolution);

    return {
      fps,
      durationInFrames: getTimelineDurationInFrames(config, fps),
      compositionWidth: Math.max(1, width),
      compositionHeight: Math.max(1, height),
    };
  }, [config]);

  useEffect(() => {
    const player = playerRef.current;
    if (!player) {
      return;
    }

    const onFrameUpdate = (event: { detail: { frame: number } }) => {
      onTimeUpdate(event.detail.frame / metadata.fps);
    };
    const onPlay = () => setIsPlaying(true);
    const onPause = () => setIsPlaying(false);

    player.addEventListener('frameupdate', onFrameUpdate);
    player.addEventListener('play', onPlay);
    player.addEventListener('pause', onPause);

    return () => {
      player.removeEventListener('frameupdate', onFrameUpdate);
      player.removeEventListener('play', onPlay);
      player.removeEventListener('pause', onPause);
    };
  }, [metadata.fps, onTimeUpdate]);

  useImperativeHandle(ref, () => ({
    seek(time: number) {
      playerRef.current?.seekTo(Math.max(0, Math.round(time * metadata.fps)));
    },
    play() {
      playerRef.current?.play();
    },
    pause() {
      playerRef.current?.pause();
    },
    togglePlayPause() {
      playerRef.current?.toggle();
    },
    get isPlaying() {
      return playerRef.current?.isPlaying() ?? isPlaying;
    },
  }), [isPlaying, metadata.fps]);

  return (
    <div
      ref={playerContainerRef}
      className="relative flex h-full min-h-[220px] w-full items-center justify-center overflow-hidden rounded-xl bg-zinc-950"
    >
      <Player
        ref={playerRef}
        component={TimelineRenderer}
        inputProps={inputProps}
        durationInFrames={metadata.durationInFrames}
        fps={metadata.fps}
        compositionWidth={metadata.compositionWidth}
        compositionHeight={metadata.compositionHeight}
        controls={false}
        clickToPlay={false}
        doubleClickToFullscreen={false}
        spaceKeyToPlayOrPause={false}
        showVolumeControls={false}
        style={{ width: '100%', height: '100%' }}
      />
      <div className="pointer-events-none absolute inset-x-0 bottom-0 flex items-center justify-center gap-2 bg-gradient-to-t from-black/60 to-transparent px-3 py-3">
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="pointer-events-auto h-8 w-8 rounded-full border-white/20 bg-black/40 text-white hover:bg-black/60"
          onClick={() => playerRef.current?.seekTo(0)}
          title="Jump to beginning"
        >
          <SkipBack className="h-4 w-4" />
        </Button>
        <Button
          type="button"
          variant="outline"
          size="icon"
          className="pointer-events-auto h-10 w-10 rounded-full border-white/20 bg-black/40 text-white hover:bg-black/60"
          onClick={() => playerRef.current?.toggle()}
          title={isPlaying ? 'Pause' : 'Play'}
        >
          {isPlaying ? <Pause className="h-4 w-4" /> : <Play className="h-4 w-4 fill-current" />}
        </Button>
        {!compact && (
          <div className="pointer-events-none rounded-full bg-black/40 px-2 py-1 text-[10px] uppercase tracking-[0.18em] text-zinc-300">
            {config.output.resolution}
          </div>
        )}
      </div>
    </div>
  );
});

import { describe, it, expect } from 'vitest';

// Mock errorHandler to avoid pulling in toast/Supabase dependencies
import {
  getDragType,
  setGenerationDragData,
  getGenerationDropData,
  isValidDropTarget,
  isFileDrag,
  NEW_GROUP_DROPPABLE_ID,
} from '../dnd/dragDrop';
import type { GenerationDropData } from '../dnd/dragDrop';

/**
 * Create a minimal mock of React.DragEvent for testing
 */
function createMockDragEvent(overrides: {
  types?: string[];
  data?: Record<string, string>;
} = {}): React.DragEvent {
  const storedData: Record<string, string> = overrides.data ?? {};
  const types = overrides.types ?? Object.keys(storedData);

  return {
    dataTransfer: {
      types,
      effectAllowed: 'none',
      setData: (type: string, value: string) => {
        storedData[type] = value;
      },
      getData: (type: string) => storedData[type] ?? '',
    },
  } as unknown as React.DragEvent;
}

describe('getDragType', () => {
  it('returns "generation" for generation MIME type', () => {
    const event = createMockDragEvent({ types: ['application/x-generation'] });
    expect(getDragType(event)).toBe('generation');
  });

  it('returns "file" for Files type', () => {
    const event = createMockDragEvent({ types: ['Files'] });
    expect(getDragType(event)).toBe('file');
  });

  it('returns "none" for unknown types', () => {
    const event = createMockDragEvent({ types: ['text/plain'] });
    expect(getDragType(event)).toBe('none');
  });

  it('returns "none" for empty types', () => {
    const event = createMockDragEvent({ types: [] });
    expect(getDragType(event)).toBe('none');
  });

  it('prefers generation over file when both present', () => {
    const event = createMockDragEvent({ types: ['application/x-generation', 'Files'] });
    expect(getDragType(event)).toBe('generation');
  });
});

describe('isFileDrag', () => {
  it('returns true when Files type present', () => {
    const event = createMockDragEvent({ types: ['Files'] });
    expect(isFileDrag(event)).toBe(true);
  });

  it('returns false when no Files type', () => {
    const event = createMockDragEvent({ types: ['text/plain'] });
    expect(isFileDrag(event)).toBe(false);
  });
});

describe('setGenerationDragData / getGenerationDropData round-trip', () => {
  it('round-trips generation data through set and get', () => {
    const data: GenerationDropData = {
      generationId: 'gen-123',
      imageUrl: 'https://example.com/img.png',
      thumbUrl: 'https://example.com/thumb.png',
      metadata: { prompt: 'a cat' },
    };

    const storedData: Record<string, string> = {};
    const setEvent = createMockDragEvent({ data: storedData });
    setGenerationDragData(setEvent, data);

    // Verify data was stored
    expect(storedData['application/x-generation']).toBeTruthy();

    const getEvent = createMockDragEvent({
      types: ['application/x-generation'],
      data: storedData,
    });
    const result = getGenerationDropData(getEvent);

    expect(result).toEqual(data);
  });

  it('returns null when no data in dataTransfer', () => {
    const event = createMockDragEvent({ data: {} });
    expect(getGenerationDropData(event)).toBeNull();
  });

  it('returns null for malformed JSON', () => {
    const event = createMockDragEvent({
      data: { 'application/x-generation': 'not-json' },
    });
    expect(getGenerationDropData(event)).toBeNull();
  });

  it('returns null when required fields missing', () => {
    const event = createMockDragEvent({
      data: { 'application/x-generation': JSON.stringify({ generationId: 'gen-1' }) }, // missing imageUrl
    });
    expect(getGenerationDropData(event)).toBeNull();
  });

  it('falls back to text/plain data', () => {
    const data: GenerationDropData = {
      generationId: 'gen-456',
      imageUrl: 'https://example.com/img.png',
    };

    const event = createMockDragEvent({
      data: { 'text/plain': JSON.stringify(data) },
    });
    const result = getGenerationDropData(event);
    expect(result).toEqual(data);
  });
});

describe('isValidDropTarget', () => {
  it('returns true for generation drag', () => {
    const event = createMockDragEvent({ types: ['application/x-generation'] });
    expect(isValidDropTarget(event)).toBe(true);
  });

  it('returns true for file drag', () => {
    const event = createMockDragEvent({ types: ['Files'] });
    expect(isValidDropTarget(event)).toBe(true);
