              <Select
                value={clip.continuous?.type ?? NO_EFFECT}
                onValueChange={(value) => onChange({ continuous: value === NO_EFFECT ? undefined : { type: value, intensity: clip.continuous?.intensity ?? 0.5 } })}
              >
                <SelectTrigger><SelectValue placeholder="None" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value={NO_EFFECT}>None</SelectItem>
                  {continuousEffectTypes.map((effect) => <SelectItem key={effect} value={effect}>{effect}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
          </div>
          <div className="rounded-lg border border-zinc-800 bg-zinc-900/50 p-3">
            <div className="mb-2 flex items-center justify-between">
              <div className="text-xs font-medium text-zinc-100">Custom effects</div>
              <Button type="button" size="sm" variant="secondary" className="gap-1" onClick={() => setShowCustomEditor((value) => !value)}>
                <Wand2 className="h-3.5 w-3.5" />
                {showCustomEditor ? 'Hide' : 'Edit'}
              </Button>
            </div>
            {showCustomEditor && (
              <CustomEffectEditor
                category={customEffectCategory}
                initialSlug={clip.continuous?.type?.replace(/^custom:/, '')}
                onApply={(slug, category) => {
                  if (category === 'entrance') {
                    onChange({ entrance: { type: `custom:${slug}`, duration: clip.entrance?.duration ?? 0.4 } });
                    return;
                  }
                  if (category === 'exit') {
                    onChange({ exit: { type: `custom:${slug}`, duration: clip.exit?.duration ?? 0.4 } });
                    return;
                  }
                  onChange({ continuous: { type: `custom:${slug}`, intensity: clip.continuous?.intensity ?? 0.5 } });
                }}
              />
            )}
          </div>
        </TabsContent>

        <TabsContent value="timing" className="space-y-3">
          <div className="grid gap-3 md:grid-cols-2">
            <div className="space-y-2">
              <FieldLabel>Start (seconds)</FieldLabel>
              <Input type="number" value={clip.at} onChange={(event) => onChange({ at: Number(event.target.value) })} />
            </div>
            <div className="space-y-2">
              <FieldLabel>Speed</FieldLabel>
              <Input type="number" value={clip.speed ?? 1} step="0.1" onChange={(event) => onChange({ speed: Number(event.target.value) })} />
            </div>
            <div className="space-y-2">
              <FieldLabel>Source In</FieldLabel>
              <Input type="number" value={clip.from ?? 0} step="0.1" onChange={(event) => onChange({ from: Number(event.target.value) })} />
            </div>
            <div className="space-y-2">
              <FieldLabel>Source Out</FieldLabel>
              <Input type="number" value={clip.to ?? clip.assetEntry?.duration ?? 5} step="0.1" onChange={(event) => onChange({ to: Number(event.target.value) })} />
            </div>
          </div>
        </TabsContent>

        <TabsContent value="position" className="space-y-3">
          <div className="grid gap-3 md:grid-cols-2">
            <div className="space-y-2">
              <FieldLabel>X</FieldLabel>
              <Input type="number" value={clip.x ?? 0} onChange={(event) => onChange({ x: Number(event.target.value) })} />
            </div>
            <div className="space-y-2">
              <FieldLabel>Y</FieldLabel>
              <Input type="number" value={clip.y ?? 0} onChange={(event) => onChange({ y: Number(event.target.value) })} />
            </div>
            <div className="space-y-2">
              <FieldLabel>Width</FieldLabel>
              <Input type="number" max={compositionWidth} value={clip.width ?? compositionWidth} onChange={(event) => onChange({ width: Number(event.target.value) })} />
            </div>
            <div className="space-y-2">
              <FieldLabel>Height</FieldLabel>
              <Input type="number" max={compositionHeight} value={clip.height ?? compositionHeight} onChange={(event) => onChange({ height: Number(event.target.value) })} />
            </div>
          </div>
          <div className="space-y-2">
            <FieldLabel>Opacity</FieldLabel>
            <Slider
              value={[clip.opacity ?? 1]}
              min={0}
              max={1}
              step={0.05}
              onValueChange={([value]) => onChange({ opacity: value })}
            />
          </div>
          <Button type="button" variant="outline" size="sm" onClick={onResetPosition}>
            Reset position
          </Button>
        </TabsContent>

        <TabsContent value="audio" className="space-y-3">
          <div className="rounded-lg border border-zinc-800 bg-zinc-900/50 p-3">
            <div className="mb-2 flex items-center gap-2 text-sm text-zinc-100">
              <Volume2 className="h-4 w-4" />
              Volume
            </div>
            <Slider
              value={[clip.volume ?? 1]}
              min={0}
              max={1}
              step={0.05}
              onValueChange={([value]) => onChange({ volume: value })}
            />
            <Button type="button" variant="secondary" size="sm" className="mt-3" onClick={onToggleMute}>
              Toggle mute
            </Button>
          </div>
        </TabsContent>

        <TabsContent value="text" className="space-y-3">
          {clip.clipType === 'text' ? (
            <>
              <Textarea
                value={clip.text?.content ?? ''}
                onChange={(event) => onChange({ text: { ...(clip.text ?? { content: '' }), content: event.target.value } })}
                rows={5}
              />
              <div className="grid gap-3 md:grid-cols-2">
                <div className="space-y-2">
                  <FieldLabel>Font size</FieldLabel>
                  <Input
                    type="number"
                    value={clip.text?.fontSize ?? 64}
                    onChange={(event) => onChange({ text: { ...(clip.text ?? { content: '' }), fontSize: Number(event.target.value) } })}
                  />
                </div>
                <div className="space-y-2">
                  <FieldLabel>Color</FieldLabel>
                  <Input
                    type="color"
                    value={clip.text?.color ?? '#ffffff'}
                    onChange={(event) => onChange({ text: { ...(clip.text ?? { content: '' }), color: event.target.value } })}
                  />
                </div>
              </div>
            </>
          ) : (
            <div className="rounded-lg border border-dashed border-zinc-800 p-4 text-sm text-zinc-500">
              The selected clip is not a text clip.
            </div>
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Textarea } from '@/shared/components/ui/textarea';
import { toast } from '@/shared/components/ui/toast';
import { useVideoEditorRuntime } from '@/tools/video-editor/contexts/DataProviderContext';
import { deleteDraftEffect, loadDraftEffects, saveDraftEffect } from '@/tools/video-editor/effects/effect-store';
import { getEffectPromptTemplate } from '@/tools/video-editor/effects/effectPromptTemplate';
import { useEffects } from '@/tools/video-editor/hooks/useEffects';
import type { CustomEffectEntry } from '@/tools/video-editor/types';

interface CustomEffectEditorProps {
  category: CustomEffectEntry['category'];
  initialSlug?: string;
  onApply: (slug: string, category: NonNullable<CustomEffectEntry['category']>) => void;
}

const TEMPLATE = `export default function Effect({ children, durationInFrames, effectFrames = 20, intensity = 0.5 }) {\n  const frame = useCurrentFrame();\n  const opacity = interpolate(frame, [0, effectFrames], [0, 1], { extrapolateRight: 'clamp' });\n\n  return (\n    <AbsoluteFill style={{ opacity }}>\n      {children}\n    </AbsoluteFill>\n  );\n}`;

export function CustomEffectEditor({ category, initialSlug, onApply }: CustomEffectEditorProps) {
  const { userId } = useVideoEditorRuntime();
  const effects = useEffects(userId);
  const existingEffect = useMemo(
    () => effects.data?.find((effect) => effect.slug === initialSlug) ?? null,
    [effects.data, initialSlug],
  );
  const [name, setName] = useState(existingEffect?.name ?? initialSlug ?? '');
  const [slug, setSlug] = useState(existingEffect?.slug ?? initialSlug ?? '');
  const [description, setDescription] = useState(existingEffect?.description ?? '');
  const [code, setCode] = useState(existingEffect?.code ?? loadDraftEffects()[initialSlug ?? ''] ?? TEMPLATE);

  useEffect(() => {
    if (!existingEffect) {
      return;
    }

    setName(existingEffect.name ?? existingEffect.slug);
    setSlug(existingEffect.slug);
    setDescription(existingEffect.description ?? '');
    setCode(existingEffect.code);
  }, [existingEffect]);

  return (
    <div className="space-y-3 rounded-lg border border-zinc-800 bg-zinc-900/60 p-3">
      <div className="space-y-2">
        <Input
          value={name}
          placeholder="Effect name"
          onChange={(event) => {
            const nextName = event.target.value;
            setName(nextName);
            if (!slug) {
              setSlug(nextName.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-'));
            }
          }}
        />
        <Input
          value={slug}
          placeholder="slug"
          onChange={(event) => setSlug(event.target.value.toLowerCase().trim().replace(/[^a-z0-9-]+/g, '-'))}
        />
        <Textarea
          value={description}
          placeholder="Describe what this effect should do"
          onChange={(event) => setDescription(event.target.value)}
          rows={2}
        />
      </div>
      <Textarea
        value={code}
        onChange={(event) => setCode(event.target.value)}
        rows={12}
        className="font-mono text-xs"
      />
      <div className="rounded-md border border-zinc-800 bg-black/30 p-2 text-[11px] text-zinc-400 whitespace-pre-wrap">
        {getEffectPromptTemplate(description || 'Create a tasteful animated effect.')}
      </div>
      <div className="flex flex-wrap gap-2">
        <Button
          type="button"
          size="sm"
          variant="secondary"
          onClick={() => {
            if (!slug) {
              toast({ title: 'Missing slug', description: 'Choose a slug before saving a draft.', variant: 'destructive' });
              return;
            }
            saveDraftEffect(slug, code);
            toast.success('Draft effect saved');
          }}
        >
          Test Draft
        </Button>
        <Button
          type="button"
          size="sm"
          onClick={async () => {
            if (!name || !slug) {
              toast({ title: 'Missing fields', description: 'Name and slug are required.', variant: 'destructive' });
              return;
            }

            await effects.upsertEffect.mutateAsync({
              id: existingEffect?.id,
              name,
              slug,
              code,
              category: category ?? 'continuous',
              description: description || null,
            });
            deleteDraftEffect(slug);
            onApply(slug, category ?? 'continuous');
            toast.success('Effect saved');
          }}
          disabled={effects.upsertEffect.isPending}
        >
          Save
        </Button>
        <Button
          type="button"
          size="sm"
          variant="outline"
          onClick={() => {
            if (slug) {
              deleteDraftEffect(slug);
            }
            setCode(existingEffect?.code ?? TEMPLATE);
          }}
        >
          Discard
        </Button>
      </div>
    </div>
  );
}
